            }
        };

        double t0 = 0.0;
        double[] y0 = new double[] { 1000.0 };
        double t1 = 1.0;
        double[] y = new double[1];

        double[] vecAbs = new double[] { 1.0e-6 };
        double[] vecRel = new double[] { 1.0e-3 };

        for (int nSteps = 4; nSteps <= 6; ++nSteps) {
